// Re-instantiate both per-index forall ensures. Each run's forall uses
// post{1,2}_self_.page_array@[i] as a trigger, so they never fire together
// at the file level (z3 returns `unknown`). Re-asserting them here forces
// both quantifiers into the local context with their triggers active.
assert(forall|i: int|
    #![trigger post1_self_.page_array@[i]]
    #![trigger pre_self_.page_array@[i]]
    0 <= i < NUM_PAGES && i != index ==> post1_self_.page_array@[i] =~= pre_self_.page_array@[i]);
assert(forall|i: int|
    #![trigger post2_self_.page_array@[i]]
    #![trigger pre_self_.page_array@[i]]
    0 <= i < NUM_PAGES && i != index ==> post2_self_.page_array@[i] =~= pre_self_.page_array@[i]);

// At the modified index, every field of Page matches pointwise between the
// two runs (each =~= the corresponding pre field, and .owning_container =~=
// owning_container_op for both). Struct extensionality (=~=) then collapses
// these field-wise equalities into a single Page-level equality.
assert(post1_self_.page_array@[index as int]
    =~= post2_self_.page_array@[index as int]);

// Pointwise: for every index in range, post1 and post2 agree on page_array@[i].
// The case split exposes the two ways the conclusion is derived to z3.
assert forall|i: int| 0 <= i < NUM_PAGES implies
    post1_self_.page_array@[i] =~= post2_self_.page_array@[i] by {
    if i == index as int {
        // Closed by the struct-extensionality assert above.
    } else {
        // Both post1.page_array@[i] and post2.page_array@[i] =~= pre.page_array@[i]
        // by the re-asserted foralls (which now share the trigger pre.page_array@[i]).
    }
}

// Sequence extensionality lifts pointwise equality of page_array@ to the
// view-level equality the determinism predicate consumes.
assert(post1_self_.page_array@ =~= post2_self_.page_array@);
